args.TargetContent:
"                {/* Candidate Results Summary Bar */}
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 px-6">
                  {/* Abas de filtro: Todos e Salvos */}
                  <div className="flex items-center gap-4 w-full sm:w-auto">
                    <div className="flex bg-slate-100/80 p-0.5 rounded-full border border-slate-200/30">
                      <button
                        type="button"
                        onClick={() => setTalentTab('todos')}
                        className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-wider transition-all cursor-pointer border-0 outline-none ${
                          talentTab === 'todos'
                            ? 'bg-slate-900 text-white shadow-sm'
                            : 'text-slate-500 hover:text-slate-800 bg-transparent'
                        }`}
                      >
                        Todos ({filteredTalents.length})
                      </button>
                      <button
                        type="button"
                        onClick={() => setTalentTab('salvos')}
                        className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-wider transition-all cursor-pointer border-0 outline-none ${
                          talentTab === 'salvos'
                            ? 'bg-slate-900 text-white shadow-sm'
                            : 'text-slate-500 hover:text-slate-800 bg-transparent'
                        }`}
                      >
                        Salvos ({filteredTalents.filter(t => savedTalentIds.includes(t.id)).length})
                      </button>
                    </div>
                  </div>"
